132	    // and returned before any notification runs, so a `notify` failure provably
133	    // cannot lose the record (settled #8). A `StorageError` here aborts the
134	    // submission (losing a record must never look like success).
135	    const stored = yield* submissions.persist(config.form, decoded.success);
