 84	 */
 85	export const registrationAction = <E>(config: RegistrationActionConfig<E>) =>
 86	  routeFormAction(function* () {
 87	    const { url } = yield* ReactRouterContext;
 88	    const submission = yield* SubmissionContext;
 89	    const content = yield* Content.Service;
 90	    const submissions = yield* Submissions.Service;
 91	    const toast = yield* Toast;
 92	
 93	    const definition = yield* content.getForm('registration');
 94	
 95	    // The registrant-array shell is registration's own concern (registration-spec
 96	    // §"Scope boundary"): the engine owns ONE registrant's graph, the route owns
