109	    // Persist each registrant FIRST — one durable `submissions/registration/<id>.json`
110	    // object apiece, written + returned before any notification runs, so a `notify`
111	    // failure provably cannot lose a record (settled #8). A `StorageError` aborts the
112	    // submission (losing a registrant must never look like success).
113	    const stored: Array<Submission> = [];
114	    for (const registrant of decoded.success.registrants) {
115	      stored.push(yield* submissions.persist('registration', registrant));
